17	interface QuoteStep {
18	  op: "quote";
19	  items: Item[];
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policyIndex: number;
25	  damages: Damage[];
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: Customer;
32	  steps: Step[];
33	}
34	
35	interface QuoteResult {
36	  premium: number;
37	}
38	
39	interface ClaimResult {
40	  payout: number;
41	}
42	
43	interface ScenarioResult {
44	  results: (QuoteResult | ClaimResult)[];
45	}
46	
47	const PROCESSING_FEE = 5;
48	
49	const BASE_PREMIUMS: Record<string, number> = {
50	  sword: 100,
51	  amulet: 60,
52	  staff: 80,
53	  potion: 40,
54	  rune: 25,
55	  moonstone: 25,
56	};
57	
58	const COMPONENT_TYPES = ["rune", "moonstone"];
59	const BLOCK_SIZE = 3;
60	const BLOCK_PREMIUM = 60;
61	
62	const isComponent = (item: Item): boolean =>
63	  COMPONENT_TYPES.includes(item.type);
64	
65	const itemBasePremium = (item: Item): number =>
66	  BASE_PREMIUMS[item.type] ?? 0;
67	
68	const itemPremiumWithModifiers = (item: Item): number => {
69	  const base = itemBasePremium(item);
70	  return base
71	    + (item.cursed ? base * 0.5 : 0)
72	    + ((item.enchantment ?? 0) >= 5 ? base * 0.3 : 0);
73	};
74	
75	const regularItems = (items: Item[]): Item[] =>
76	  items.filter((item) => !isComponent(item));
77	
78	const regularItemsPremium = (items: Item[]): number =>
79	  regularItems(items)
80	    .reduce((sum, item) => sum + itemPremiumWithModifiers(item), 0);
81	
82	const componentBlockPremium = (count: number, type: string): number =>
83	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
84	
85	const countComponentsByType = (items: Item[]): Record<string, number> =>
86	  items.filter(isComponent).reduce(
87	    (acc: Record<string, number>, item) => ({
88	      ...acc,
89	      [item.type]: (acc[item.type] ?? 0) + 1,
90	    }),
91	    {},
92	  );
93	
94	const componentsPremium = (items: Item[]): number =>
95	  Object.entries(countComponentsByType(items)).reduce(
96	    (sum, [type, count]) => sum + componentBlockPremium(count, type),
97	    0,
98	  );
99	
100	const policyBasePremium = (items: Item[]): number =>
101	  regularItems(items)
102	    .reduce((sum, item) => sum + itemBasePremium(item), 0)
103	  + componentsPremium(items);
104	
105	const policyWideModifierRate = (customer: Customer, quoteIndex: number): number =>
106	  0.1 + (customer.yearsWithMHPCO >= 2 ? -0.2 : 0) + (quoteIndex > 0 ? -0.15 : 0);
107	
108	const validateItemTypes = (items: Item[]): void => {
109	  const unknownItem = items.find((item) => !(item.type in BASE_PREMIUMS));
110	  if (unknownItem) {
111	    throw new Error(`Unknown item type: ${unknownItem.type}`);
112	  }
113	};
114	
115	const calculateQuotePremium = (items: Item[], customer: Customer, quoteIndex: number): number => {
116	  validateItemTypes(items);
117	  const itemsTotal = regularItemsPremium(items) + componentsPremium(items);
118	  const policyModifier = policyBasePremium(items) * policyWideModifierRate(customer, quoteIndex);
119	  return Math.ceil(itemsTotal + policyModifier + PROCESSING_FEE);
120	};
