47	const PROCESSING_FEE = 5;
48	
49	const BASE_PREMIUMS: Record<string, number> = {
50	  sword: 100,
51	  amulet: 60,
52	  staff: 80,
53	  potion: 40,
54	  rune: 25,
55	  moonstone: 25,
